updates.log_tab_tap:
function(doc, req) {
      if (!doc || doc._id === '_design/viewEvents') {
        return [null, 'no doc'];
      }

      var body = {};
      if (req.body) {
        try { body = JSON.parse(req.body); } catch(e) {}
      }

      var event = {
        viewer: body.viewer || req.userCtx.name || 'anonymous',
        session_id: body.session_id || req.query.session_id || 'unknown',
        test_status: doc.test_status || 'unknown',
        tab_status: 'details',
        timestamp: new Date().toISOString()
      };

      if (!doc.view_events) doc.view_events = [];
      doc.view_events.push(event);

      return [doc, JSON.stringify({ok: true, event: event})];
    }
